  <div class="pt">
  <svg viewBox="0 0 700 340" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Para onde foram os fundos retirados da Binance após o MiCA</text>
    <text x="20" y="50" fill="#a1a1aa" font-size="13" font-family="sans-serif">Co-CEO Richard Teng, Reuters NEXT Asia (9 de julho de 2026)</text>
    <g font-family="sans-serif">
      <text x="20" y="100" fill="#fafafa" font-size="14" font-weight="700">Carteiras de autocustódia</text>
      <rect x="20" y="112" width="490" height="40" fill="#f43f5e"/>
